--
-- Table structure for table `caipiao_huodong`
--

DROP TABLE IF EXISTS `caipiao_huodong`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `caipiao_huodong` (
  `id` int(11) NOT NULL AUTO_INCREMENT COMMENT 'ID khuyến mãi',
  `title` varchar(255) NOT NULL COMMENT 'tiêu đề khuyến mãi',
  `desc` varchar(500) DEFAULT NULL COMMENT 'Hoạt động',
  `content` text COMMENT 'Hoạt độngnội dung(HTM L)',
  `terms` text COMMENT '',
  `banner` varchar(500) DEFAULT NULL COMMENT 'hình ảnh banner',
  `images` text COMMENT 'hình ảnh chi tiết(JSO N)',
  `type` varchar(20) DEFAULT 'other' COMMENT 'Hoạt động Loại: deposit(nạp tiền)/reward(thưởng)/other()',
  `category` varchar(50) DEFAULT 'all' COMMENT 'danh mục khuyến mãimã',
  `type_code` varchar(50) DEFAULT NULL COMMENT 'loại khuyến mãimã',
  `start_date` date DEFAULT NULL COMMENT '',
  `end_date` date DEFAULT NULL COMMENT '',
  `start_time` int(11) DEFAULT NULL COMMENT 'thời gian',
  `end_time` int(11) DEFAULT NULL COMMENT 'thời gian',
  `status` tinyint(1) DEFAULT '1' COMMENT 'Trạng thái: 1=Kích hoạt, 0=Vô hiệu hóa',
  `sort` int(11) DEFAULT '0' COMMENT 'Sắp xếp',
  `jump_type` tinyint(1) NOT NULL DEFAULT '0' COMMENT 'Loại: 0=chi tiết mặc định 1=điểm danh 2=UR L',
  `jump_url` varchar(500) DEFAULT '' COMMENT 'UR L',
  `required_deposit` decimal(10,2) DEFAULT '0.00' COMMENT 'điểm danhnạp tiền Số tiền',
  `required_bet` decimal(10,2) DEFAULT '0.00' COMMENT 'điểm danhđặt cược Số tiền',
  `created_at` int(11) DEFAULT NULL COMMENT 'Thời gian tạo',
  `updated_at` int(11) DEFAULT NULL COMMENT 'Thời gian cập nhật',
  PRIMARY KEY (`id`),
  KEY `idx_type` (`type`),
  KEY `idx_status` (`status`),
  KEY `idx_sort` (`sort`),
  KEY `idx_time` (`start_time`,`end_time`),
  KEY `idx_category` (`category`),
  KEY `idx_type_code` (`type_code`),
  KEY `idx_game_category_code` (`category`),
  KEY `idx_activity_type_code` (`type_code`)
) ENGINE=InnoDB AUTO_INCREMENT=25 DEFAULT CHARSET=utf8mb4 COMMENT='Hoạt độngBảng';
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `caipiao_huodong`
--

LOCK TABLES `caipiao_huodong` WRITE;
/*!40000 ALTER TABLE `caipiao_huodong` DISABLE KEYS */;
INSERT INTO `caipiao_huodong` VALUES (12,'mới人Gói quà 首存Tiền thưởng','','<p>&lt;div style=\"text-align: center;\"&gt;&lt;h2 style=\"font-size: 18px; font-weight: bold; margin: 10px 0;\"&gt;mới人Gói quà&lt;/h2&gt;&lt;/div&gt;&lt;p style=\"font-size: 14px; font-weight: bold; margin: 8px 0;\"&gt;Hoạt động对象：mớiĐăng kýThành viên&lt;/p&gt;&lt;p style=\"font-size: 14px; font-weight: bold; margin: 8px 0;\"&gt;Hoạt độngThời gian：2024.03.24（即ngày起）&lt;/p&gt;&lt;p style=\"font-size: 14px; font-weight: bold; margin: 8px 0;\"&gt;Hoạt độngChi tiết：&lt;/p&gt;&lt;p&gt;&lt;img src=\"https://web.hwyla8.net/siteadmin/upload/img/1771866511772987393.avif\" style=\"max-width: 100%; display: block; margin: 10px auto;\"&gt;&lt;/p&gt;&lt;p style=\"font-size: 14px; line-height: 1.7;\"&gt;&lt;strong&gt;&lt;span style=\"color: #169179;\"&gt;例：&lt;/span&gt;mớiĐăng kýThành viên在24giờ内首次Nạp tiền1000USDT，即可申vui lòng18USDTmới人Gói quà，&lt;/strong&gt;&lt;/p&gt;&lt;p style=\"font-size: 14px; line-height: 1.7;\"&gt;&lt;strong&gt;&lt;span style=\"color: #169179;\"&gt;—倍Doanh thu cược&lt;/span&gt; 即可Rút tiền！&lt;/strong&gt;&lt;/p&gt;&lt;p style=\"font-size: 14px; margin-top: 15px;\"&gt;&lt;strong&gt;申vui lòng方式：联系TGCSKH &lt;a href=\"https://t.me/hwyx10\" style=\"color: #169179; text-decoration: none;\"&gt;@hwyx10&lt;/a&gt;&lt;/strong&gt;&lt;/p&gt;&lt;p style=\"font-size: 14px;\"&gt;&lt;strong&gt;点击Người dùng名可直接跳转咨询&lt;/strong&gt;&lt;/p&gt;&lt;p style=\"font-size: 14px; font-weight: bold; margin: 15px 0 10px 0;\"&gt;Hoạt độngQuy tắc：&lt;/p&gt;&lt;p style=\"font-size: 14px; line-height: 1.7; margin-bottom: 8px;\"&gt;&lt;strong&gt;1、符合申vui lòng条件的Thành viênvui lòng在&lt;span style=\"color: #169179;\"&gt;Đăng ký24giờ内&lt;/span&gt;申vui lòng，逾期视为自动放弃Khuyến mãi；&lt;/strong&gt;&lt;/p&gt;&lt;p style=\"font-size: 14px; line-height: 1.7; margin-bottom: 8px;\"&gt;&lt;strong&gt;2、Thành viên需在Nạp tiền后且未进行任何Đặt cược，如未申vui lònghoặc在申vui lòng前进行Đặt cược，则视为放弃参与该Khuyến mãi；&lt;/strong&gt;&lt;/p&gt;&lt;p style=\"font-size: 14px; line-height: 1.7; margin-bottom: 8px;\"&gt;&lt;strong&gt;3、参与首存Hoạt động，&lt;span style=\"color: #169179;\"&gt;禁止无风险Đặt cược，禁止Đặt cược电子游艺（桌面游戏，轮盘游戏等），棋牌游戏（lớnnhỏ，单双，trăm家乐，龙虎斗等50%概率的游戏）&lt;/span&gt;，否则将扣除Khuyến mãi，并退还本金到游戏账户，完成一倍Doanh thu cược即可正常取款！&lt;/strong&gt;&lt;/p&gt;&lt;p style=\"font-size: 14px; line-height: 1.7; margin-bottom: 8px;\"&gt;&lt;strong&gt;4、每位Thành viênIP地址只能享có一次Khuyến mãi，若Thành viênnhiềuIP重复申vui lòngTài khoản行为，公司保留取消hoặc收回Thành viênTiền thưởng的权利；&lt;/strong&gt;&lt;/p&gt;&lt;p style=\"font-size: 14px; line-height: 1.7; margin-bottom: 8px;\"&gt;&lt;strong&gt;5、所获Tiền thưởng&lt;span style=\"color: #169179;\"&gt;仅限【电子游艺】【捕鱼游戏】【棋牌游戏】一倍Doanh thu cược&lt;/span&gt;即可Rút tiền；&lt;/strong&gt;&lt;/p&gt;&lt;p style=\"font-size: 14px; line-height: 1.7; margin-bottom: 8px;\"&gt;&lt;strong&gt;6、平台保留对Hoạt động的最终解释权；参与此Khuyến mãiBảng示您同意&lt;span style=\"color: #169179;\"&gt;《Khuyến mãiQuy tắc与Điều khoản》&lt;/span&gt;&lt;/strong&gt;&lt;/p&gt;</p>',NULL,'/app/admin/upload/img/20261218/69441acc432c.avif','','','all','general_activity','2026-12-19','2026-02-01',1766076946,1769875200,1,880,0,'',0.00,0.00,1766070996,1766076805),(13,'电子狂欢 mớituầnLương','','<p>&lt;div class=\"\"&gt;1.Hàng tuần电子游艺có效Đặt cược5000hoặc以上，将获得一定Số tiềnTiền thưởng，Vòng cược越nhiều，奖励越nhiều，最cao奖励2888；&lt;br&gt;2.满足条件即可领取，且不同Số tiền皆可逐一领取；&lt;br&gt;3.奖励仅限在iOS、Android、H5、Web手动领取；Hàng tuần一领取，过期作废；&lt;br&gt;4.本Hoạt động所赠送的Tiền thưởng（不含本金）需1倍Doanh thu cược（即稽核、Vòng cượchoặccó效Đặt cược）才能Rút tiền，Vòng cược不限游戏平台；&lt;br&gt;5.本Hoạt động仅限Tài khoản本人进行正常的人为操作，禁止租借、使用外挂、机器人、不同Tài khoản对赌、互刷、套利、接口、协议、利用漏洞、群控hoặc其他技术手段参与，否则将取消hoặc扣除奖励、冻结、甚至拉入黑名单；&lt;br&gt;6.为避免文字理解差异，平台将保留本Hoạt động最终解释权。&lt;/div&gt;</p>',NULL,'/app/admin/upload/img/20261218/69441e4f1ec9.avif','','','slot','weekly_salary','2026-12-19','2026-02-01',1766074735,1769875200,1,870,0,'',0.00,0.00,1766071896,1766074595),(14,'电子狂欢 幸运注单','','<p>&lt;div class=\"\"&gt;1.Thành viênHàng ngày在指定平台 【PG 电子】游戏单笔có效注单Số tiềnlớn于等于1，且该笔注单尾ngày与Hoạt động规定尾ngày相同，即可获得对应có效Đặt cược（có效Đặt cược = Đặt cượcSố tiền）额的倍数Tiền thưởng，最caoTiền thưởng上限2888；&lt;br&gt;2.Hàng ngày领取次数3次；&lt;br&gt;3.奖励仅限在iOS、Android、H5、Web手动领取，Hàng ngày过期作废（即未主动领取视为自愿放弃）；&lt;br&gt;4.本Hoạt động所赠送的Tiền thưởng（不含本金）需1倍Doanh thu cược（即稽核、Vòng cượchoặccó效Đặt cược）才能Rút tiền，Vòng cược不限游戏平台；&lt;br&gt;5.本Hoạt động仅限Tài khoản本人进行正常游戏Đặt cược，禁止租借Tài khoản、无风险Đặt cược(对赌、对刷、thấp赔刷水)、恶意套利、使用外挂程式、机器人、利用协议、漏洞、接口、群控hoặc其他技术手段参与，一经查核属实，本平台có权终止Thành viênĐăng nhập、暂停Thành viên使用网站、及没收Tiền thưởngvà不当盈利的权利，无需特别Thông báo；&lt;br&gt;6.Thành viên参与该Hoạt động时，本平台将默认Thành viên同意且遵守对应条件等相关规定，为避免文字理解歧义，平台保có本Hoạt động最终解释权。&lt;/div&gt;</p>',NULL,'/app/admin/upload/img/20261219/694431d29db6.avif','','','slot','lucky_order','2026-12-19','2026-02-01',1766073600,1769875200,1,860,0,'',0.00,0.00,1766076894,1766082079),(15,'亏损救援金','','<p>&lt;div class=\"\"&gt;Hoạt động游戏：电子 棋牌 捕鱼&lt;br&gt;Hoạt động要求：按照对应比例Hàng ngày总亏损（扣除Khuyến mãi）达到要求标准&lt;br&gt;稽核Vòng cược：Tiền thưởng5倍Doanh thu cược（稽核仅限于电子棋牌捕鱼）Hàng ngày领取上限1888&lt;br&gt;领取方式：手动领取，过期自动派发&lt;br&gt;为避免文字理解差异，平台保留最终解释权&lt;br&gt;参与该Khuyến mãiBảng示您已同意《Khuyến mãiQuy tắc与Điều khoản》&lt;/div&gt;</p>','','/app/admin/upload/img/20261219/694441f0f615.avif','','','slot,fish,chess','loss_rescue','2026-12-19','2026-02-01',1766073600,1769875200,1,850,0,'',0.00,0.00,1766081072,1766087835),(16,'电子狂欢 爆奖加赠iPhone 16 Pro Max','','<h1>&lt;div class=\"cusomize-content cusomize-content\" style=\"padding-left: 0.2rem; padding-right: 0.2rem; min-height: calc(var(--lobby__screen-height) - 0.4rem - 0.4rem - 0.9rem - 1.6rem);\"&gt;&lt;div id=\"person_temp3_5\" class=\"\" data-v-37a20f08=\"\"&gt;</h1><h1>&lt;div id=\"person_head\" class=\"\" data-v-37a20f08=\"\"&gt;</h1><h1>&lt;div class=\"person_lookcont\" data-v-37a20f08=\"\"&gt;</h1><h1>&lt;div class=\"person_looksubcont\" data-v-37a20f08=\"\"&gt;</h1><h1>&lt;p class=\"p1\" style=\"margin: 0rem; font-variant-numeric: normal; font-variant-east-asian: normal; font-variant-alternat